function: () => {
  const iframe = document.querySelector('#rol-finance-reports-views .view.active iframe')
    || document.querySelector('#rol-finance-reports-views iframe');
  if (!iframe) return { error: 'no iframe', activeView: document.querySelector('#rol-finance-reports-views .view.active')?.id };
  const doc = iframe.contentDocument;
  if (!doc) return { error: 'no contentDocument', src: iframe.src };
  const sections = [...doc.querySelectorAll('main > section, body > section')].map(s => ({
    heading: (s.querySelector('h1,h2,h3')?.textContent || s.className).trim().slice(0,40),
    display: s.ownerDocument.defaultView.getComputedStyle(s).display,
  }));
  return { src: iframe.src, sections };
}

