function: () => {
  const iframe = document.querySelector('#rol-finance-reports-views .view.active iframe')
    || document.querySelector('#rol-finance-reports-views iframe');
  if (!iframe) return { error: 'no iframe' };
  const doc = iframe.contentDocument;
  const row = doc.querySelector('#verified-transactions tbody tr');
  if (!row) return { error: 'no row', src: iframe.src };
  doc.defaultView.openCategoryPicker(row);
  const squares = [...doc.querySelectorAll('#rol-category-picker .cp-square')].map(s => ({
    name: s.textContent,
    bg: s.style.background,
  }));
  return { src: iframe.src, count: squares.length, squares };
}
